const item = $input.first();
const headers = item.json.headers || {};
const body = item.json.body ?? item.json;

const expectedSecret = ($vars.NOTIFICATION_WEBHOOK_SECRET || '').trim();
const inboundSecret = String(
  headers['x-notification-secret'] ||
  headers['X-Notification-Secret'] ||
  ''
).trim();

if (expectedSecret && inboundSecret !== expectedSecret) {
  return [{ json: { ok: false, authorized: false, error: 'Invalid notification secret' } }];
}

const to = String(body.to || '').trim();
if (!to) {
  return [{ json: { ok: false, authorized: true, error: 'Missing recipient email (to)' } }];
}

const appUrl = 'https://codex.itsnomatata.com';
const fullName = String(body.fullName || 'Team Member').trim() || 'Team Member';
const firstName = String(body.firstName || fullName.split(/\s+/)[0] || 'there');
const title = String(body.title || 'Notification').trim();
const message = String(body.message || title).trim();
const subject = String(body.subject || `${title} - Codex`).trim();
const metadata = body.metadata || {};
const actionPath = String(body.actionUrl || '/');
const actionUrl = actionPath.startsWith('http') ? actionPath : `${appUrl}${actionPath.startsWith('/') ? actionPath : '/' + actionPath}`;

let emailHtml = String(body.emailHtml || '').trim();
if (!emailHtml) {
  const sourceBadge = metadata.source_badge
    || (metadata.feedback_source === 'client' ? 'Client review' : metadata.feedback_source === 'internal' ? 'Internal review' : null);
  const reviewEvent = metadata.review_event ? String(metadata.review_event).replace(/_/g, ' ') : null;
  const slot = metadata.display_slot != null ? `Post ${Number(metadata.display_slot) + 1}` : null;
  const badgeStyle = sourceBadge === 'Client review'
    ? 'background:#0ea5e920;color:#0369a1;border:1px solid #0ea5e966;'
    : 'background:#f9731620;color:#c2410c;border:1px solid #f9731666;';
  const badges = sourceBadge
    ? `<p style="margin:0 0 16px;"><span style="display:inline-block;padding:6px 12px;border-radius:999px;font-size:12px;font-weight:700;${badgeStyle}">${sourceBadge}</span>${reviewEvent ? `<span style="display:inline-block;margin-left:8px;padding:6px 12px;border-radius:999px;font-size:12px;font-weight:600;background:#f4f4f5;color:#3f3f46;border:1px solid #e4e4e7;">${reviewEvent}</span>` : ''}${slot ? `<span style="display:inline-block;margin-left:8px;padding:6px 12px;border-radius:999px;font-size:12px;font-weight:600;background:#fff7ed;color:#c2410c;border:1px solid #fed7aa;">${slot}</span>` : ''}</p>`
    : '';
  emailHtml = `<div style="font-family:Arial,sans-serif;line-height:1.6;color:#111;"><p style="margin:0 0 8px;font-size:12px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:#ea580c;">Codex</p><h2 style="margin:0 0 12px;">${title}</h2>${badges}<p>Hi ${firstName},</p><p>${message.replace(/\n/g, '<br/>')}</p><p><a href="${actionUrl}" style="display:inline-block;background:#f97316;color:#000;text-decoration:none;padding:12px 18px;border-radius:8px;font-weight:700;">Open in Codex</a></p></div>`;
}

const textBody = [title, '', `Hi ${firstName},`, message, '', actionUrl].join('\n');

return [{
  json: {
    ok: true,
    authorized: true,
    to,
    fullName,
    firstName,
    title,
    message,
    subject,
    emailHtml,
    textBody,
    type: body.type || 'system_alert',
    priority: body.priority || 'medium',
    actionUrl,
    metadata,
    deliveryId: body.deliveryId || null,
    notificationId: body.notificationId || null,
    useHtml: true
  }
}];
